const out = [];
for (const item of $input.all()) {
  const row = item.json;
  const firstName = (row.first_name || '').trim() || 'there';
  const programName = row.program_name || 'your IAML program';
  const city = (row.city || '').trim();
  const instructorFirst = (row.instructor_first_name || '').trim();
  const url = 'https://iaml.com/evaluation.html?token=' + row.resume_token;
  const subject = city ? ('Your feedback on this week\'s program in ' + city) : ('Your ' + programName + ' evaluation');
  let contextClause;
  if (instructorFirst && city) contextClause = programName + ' with ' + instructorFirst + ' in ' + city;
  else if (city) contextClause = programName + ' in ' + city;
  else if (instructorFirst) contextClause = programName + ' with ' + instructorFirst;
  else contextClause = programName;
  const text = 'Hi ' + firstName + ',\n\nNow that you\'ve wrapped up ' + contextClause + ', I\'d appreciate your feedback on the program. Takes about five minutes.\n\nOpen your evaluation:\n' + url + '\n\nYour responses shape how we teach the next cohort, and flag anything our team should follow up on with you. The link is unique to you and saves as you go, so pause and return whenever works.\n\nThanks,\n\nPhoebe Harper\nDirector of Operations\nPhone: (949) 760-1700\nInstitute for Applied Management & Law, Inc.\n1024 Bayside Dr., Suite 172\nNewport Beach, CA 92660\nwww.iaml.com';
  const sigHtml = '<main style="font-family: Inter, Arial, sans-serif; font-size: 16px;"><table style="padding:0px;margin:10px 0;border:none"><tbody><tr><td style="vertical-align:middle;padding:10px 7px 0 0"><p style="line-height: 1.5;"><img style="height: 75px;width: 75px;" alt="Company logo" height="75" src="https://storage.googleapis.com/signaturesatori/customer-C043gkzsd/images/companyLogo/KBouH.png" width="75"></p></td><td style="border-left:3px solid #dddddd;padding:7px 0px 0px 10px;font-family:arial,sans-serif;font-size:12px;line-height:14px;color:#555555"><div style="margin-bottom:10px"><p style="line-height: 1.5;"><strong><span style="font-size: 14px; color: rgb(255, 152, 0)">Phoebe Harper</span></strong><br>Director of Operations</p></div><div style="margin-bottom:10px"><p style="line-height: 1.5;"><span style="color: rgb(0, 102, 255)">Phone: (949) 760-1700</span></p></div><div><p style="line-height: 1.5;"><strong>Institute for Applied Management &amp; Law, Inc.</strong><br>1024 Bayside Dr., Suite 172<br>Newport Beach, CA 92660<br><a href="https://www.iaml.com"><span style="color: rgb(0, 102, 255)">www.iaml.com</span></a></p></div></td></tr></tbody></table></main>';
  const html = '<div style="font-family: -apple-system, BlinkMacSystemFont, Inter, Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #1a1a2e; padding: 24px; line-height: 1.55;"><p style="font-size: 16px; margin: 0 0 16px;">Hi ' + firstName + ',</p><p style="font-size: 16px; margin: 0 0 16px;">Now that you&rsquo;ve wrapped up <strong>' + contextClause + '</strong>, I&rsquo;d appreciate your feedback on the program. Takes about five minutes.</p><p style="margin: 24px 0;"><a href="' + url + '" style="display: inline-block; padding: 13px 24px; background: #188BF6; color: #ffffff; text-decoration: none; border-radius: 8px; font-weight: 600; font-size: 15px;">Open your evaluation</a></p><p style="font-size: 16px; margin: 0 0 16px;">Your responses shape how we teach the next cohort, and flag anything our team should follow up on with you. The link is unique to you and saves as you go, so pause and return whenever works.</p><p style="font-size: 16px; margin: 0 0 8px;">Thanks,</p>' + sigHtml + '</div>';
  out.push({ json: { evaluation_id: row.evaluation_id, email: row.email, first_name: row.first_name, last_name: row.last_name, subject: subject, text: text, html: html } });
}
return out;

